lexer grammar SYsULexer;

// Keywords
Int : 'int';
Return : 'return';
Void : 'void';
If : 'if';
Else : 'else';
While : 'while';
For : 'for';
Break : 'break';
Continue : 'continue';

// Punctuation
LeftParen : '(';
RightParen : ')';
LeftBracket : '[';
RightBracket : ']';
LeftBrace : '{';
RightBrace : '}';
Semi : ';';
Comma : ',';

// Operators
Plus : '+';
Minus : '-';
Star : '*';
Div : '/';
Equal : '=';
Less : '<';
Greater : '>';
LessEqual : '<=';
GreaterEqual : '>=';
EqualEqual : '==';
ExclaimEqual : '!=';
Ampersand : '&';
Pipe : '|';
Caret : '^';
Tilde : '~';
Question : '?';
Colon : ':';
Exclamation : '!';
Percent : '%';
AmpersandAmpersand : '&&';
PipePipe : '||';
PlusPlus : '++';
MinusMinus : '--';
LeftShift : '<<';
RightShift : '>>';

Identifier
    :   IdentifierNondigit
        (   IdentifierNondigit
        |   Digit
        )*
    ;

fragment
IdentifierNondigit
    :   Nondigit
    ;

fragment
Nondigit
    :   [a-zA-Z_]
    ;

fragment
Digit
    :   [0-9]
    ;

Constant
    :   IntegerConstant
    ;

fragment
IntegerConstant
    :   DecimalConstant
    |   OctalConstant
    |   HexConstant
    ;

fragment
DecimalConstant
    :   NonzeroDigit Digit*
    ;

fragment
OctalConstant
    :   '0' OctalDigit*
    ;

fragment
HexConstant
    :   '0' [xX] HexDigit+
    ;

fragment
HexDigit
    :   [0-9a-fA-F]
    ;


fragment
NonzeroDigit
    :   [1-9]
    ;

fragment
OctalDigit
    :   [0-7]
    ;

// Single-line comments
SingleLineComment
    :   '//' ~[\r\n]*
        -> skip
    ;

// Multi-line comments
MultiLineComment
    :   '/*' .*? '*/'
        -> skip
    ;

// 预处理信息处理，可以从预处理信息中获得文件名以及行号
// 预处理信息中的第一个数字即为行号
LineAfterPreprocessing
    :   '#' Whitespace* ~[\r\n]*
        -> skip
    ;

Whitespace
    :   [ \t]+
        -> skip
    ;

// 换行符号，可以利用这个信息来更新行号
Newline
    :   (   '\r' '\n'?
        |   '\n'
        )
        -> skip
    ;

